#!/usr/bin/env node

import fs from 'node:fs';
import path from 'node:path';
import process from 'node:process';

/**
 * @typedef {{sha256: Record<string, string>}} ManifestTarget
 */

/**
 * @typedef {{
 *   artifact_set_revision: number,
 *   target: Record<string, ManifestTarget>,
 * }} ArtifactsManifest
 */

/**
 * @typedef {{
 *   ton_commit: string,
 *   rust_target: string,
 *   sha256_libemulator: string,
 *   sha256_libtolk: string,
 * }} TargetLock
 */

/**
 * @typedef {{
 *   inputPath: string,
 *   outputPath: string | undefined,
 *   artifactSetRevision: number,
 * }} CliArgs
 */

const HEADER_LINES = [
  '# THIS FILE IS AUTOGENERATED. DO NOT EDIT IT MANUALLY.',
  '#',
  '# Tracked revision data for native TON archives in `objs/`.',
  '# `build.rs` watches this file with `cargo:rerun-if-changed`, so bump the',
  '# revision and refresh the SHA-256 values whenever `libemulator.a` or',
  '# `libtolk.a` is refreshed.',
  '#',
  '# THIS FILE IS AUTOGENERATED. DO NOT EDIT IT MANUALLY.',
  '',
];

/** @returns {never} */
function usage() {
  console.error(
    `Usage: ${path.basename(process.argv[1])} <input-path> [output.toml] [--artifact-set-revision <integer>] (default: 1)`,
  );
  process.exit(1);
}

/**
 * @param {string} value
 * @returns {number}
 */
function parseArtifactSetRevision(value) {
  const artifactSetRevision = Number.parseInt(value, 10);
  if (!Number.isInteger(artifactSetRevision)) {
    throw new Error(`invalid artifact_set_revision: ${value}`);
  }

  return artifactSetRevision;
}

/**
 * @param {string[]} argv
 * @returns {CliArgs}
 */
function parseCliArgs(argv) {
  const positional = [];
  let artifactSetRevision = 1;

  for (let index = 2; index < argv.length; index += 1) {
    const arg = argv[index];

    if (arg === '--help' || arg === '-h') {
      usage();
    }

    if (arg === '--artifact-set-revision') {
      const value = argv[index + 1];
      if (value === undefined) {
        throw new Error('--artifact-set-revision requires a value');
      }

      artifactSetRevision = parseArtifactSetRevision(value);
      index += 1;
      continue;
    }

    if (arg.startsWith('--artifact-set-revision=')) {
      const value = arg.slice('--artifact-set-revision='.length);
      artifactSetRevision = parseArtifactSetRevision(value);
      continue;
    }

    positional.push(arg);
  }

  if (positional.length < 1 || positional.length > 2) {
    usage();
  }

  return {
    inputPath: positional[0],
    outputPath: positional[1],
    artifactSetRevision,
  };
}

/**
 * @param {unknown} value
 * @param {string} fieldName
 * @param {string} jsonPath
 * @returns {string}
 */
function readRequiredString(value, fieldName, jsonPath) {
  if (typeof value !== 'string' || value.length === 0) {
    throw new Error(`expected ${fieldName} to be a non-empty string in ${jsonPath}`);
  }

  return value;
}

/**
 * @param {unknown} value
 * @param {string} jsonPath
 * @returns {TargetLock}
 */
function parseTargetLock(value, jsonPath) {
  if (typeof value !== 'object' || value === null || Array.isArray(value)) {
    throw new Error(`expected top-level JSON object in ${jsonPath}`);
  }

  /** @type {Record<string, unknown>} */
  const targetLock = value;

  return {
    ton_commit: readRequiredString(targetLock.ton_commit, 'ton_commit', jsonPath),
    rust_target: readRequiredString(targetLock.rust_target, 'rust_target', jsonPath),
    sha256_libemulator: readRequiredString(
      targetLock.sha256_libemulator,
      'sha256_libemulator',
      jsonPath,
    ),
    sha256_libtolk: readRequiredString(targetLock.sha256_libtolk, 'sha256_libtolk', jsonPath),
  };
}

/**
 * @param {string} jsonPath
 * @returns {TargetLock}
 */
function parseTargetLockFile(jsonPath) {
  const content = fs.readFileSync(jsonPath, 'utf8');
  let parsedContent;

  try {
    parsedContent = JSON.parse(content);
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    throw new Error(`failed to parse JSON file ${jsonPath}: ${message}`);
  }

  return parseTargetLock(parsedContent, jsonPath);
}

/**
 * @param {string} inputPath
 * @returns {TargetLock[]}
 */
function parseTargetLocks(inputPath) {
  const resolvedInputPath = path.resolve(inputPath);

  if (!fs.existsSync(resolvedInputPath)) {
    throw new Error(`input path does not exist: ${inputPath}`);
  }

  const inputStat = fs.statSync(resolvedInputPath);

  if (inputStat.isDirectory()) {
    const jsonPaths = fs
      .readdirSync(resolvedInputPath, { withFileTypes: true })
      .filter((entry) => entry.isFile() && path.extname(entry.name).toLowerCase() === '.json')
      .map((entry) => path.join(resolvedInputPath, entry.name))
      .sort((left, right) => left.localeCompare(right));

    if (jsonPaths.length === 0) {
      throw new Error(`input directory contains no .json files: ${inputPath}`);
    }

    return jsonPaths.map((jsonPath) => parseTargetLockFile(jsonPath));
  }

  if (inputStat.isFile() && path.extname(resolvedInputPath).toLowerCase() === '.json') {
    return [parseTargetLockFile(resolvedInputPath)];
  }

  throw new Error(`input path must point to a .json file or a directory: ${inputPath}`);
}

/**
 * @param {TargetLock[]} targetLocks
 * @param {number} artifactSetRevision
 * @returns {ArtifactsManifest}
 */
function buildArtifactsManifest(targetLocks, artifactSetRevision) {
  if (targetLocks.length === 0) {
    throw new Error('at least one target lock is required to build the manifest');
  }

  /** @type {Record<string, ManifestTarget>} */
  const target = {};

  for (const targetLock of targetLocks) {
    const rust_target = targetLock.rust_target;

    if (target[rust_target] !== undefined) {
      throw new Error(`duplicate rust_target in input: ${rust_target}`);
    }

    target[rust_target] = {
      sha256: {
        libemulator: targetLock.sha256_libemulator,
        libtolk: targetLock.sha256_libtolk,
      },
    };
  }

  return {
    artifact_set_revision: artifactSetRevision,
    target,
  };
}

/**
 * @param {ArtifactsManifest} manifest
 * @returns {string}
 */
function renderArtifactsManifestToml(manifest) {
  const lines = [...HEADER_LINES, `artifact_set_revision = ${manifest.artifact_set_revision}`];

  const sortedTargets = Object.entries(manifest.target).sort(([left], [right]) =>
    left.localeCompare(right),
  );

  for (const [rustTarget, manifestTarget] of sortedTargets) {
    lines.push('');
    lines.push(`[target.${rustTarget}.sha256]`);
    lines.push(`libemulator = "${manifestTarget.sha256.libemulator}"`);
    lines.push(`libtolk = "${manifestTarget.sha256.libtolk}"`);
  }

  lines.push('');
  return lines.join('\n');
}

/** @returns {void} */
function main() {
  const { inputPath, outputPath, artifactSetRevision } = parseCliArgs(process.argv);
  const targetLocks = parseTargetLocks(inputPath);
  const artifactsManifest = buildArtifactsManifest(targetLocks, artifactSetRevision);
  const toml = renderArtifactsManifestToml(artifactsManifest);

  if (outputPath) {
    fs.writeFileSync(outputPath, toml);
  } else {
    process.stdout.write(toml);
  }
}

try {
  main();
} catch (error) {
  const message = error instanceof Error ? error.message : String(error);
  console.error(message);
  process.exit(1);
}
